component.schema:
{
 "description": "CapacityProvider is the Schema for the CapacityProviders API",
 "properties": {
  "spec": {
   "description": "CapacityProviderSpec defines the desired state of CapacityProvider.\n\nThe details for a capacity provider.",
   "properties": {
    "autoScalingGroupProvider": {
     "description": "The details of the Auto Scaling group for the capacity provider.",
     "properties": {
      "autoScalingGroupARN": {
       "type": "string",
       "x-kubernetes-validations": [
        {
         "message": "Value is immutable once set",
         "rule": "self == oldSelf"
        }
       ]
      },
      "autoScalingGroupRef": {
       "description": "Reference field for AutoScalingGroupARN",
       "properties": {
        "from": {
         "description": "AWSResourceReference provides all the values necessary to reference another\nk8s resource for finding the identifier(Id/ARN/Name)",
         "properties": {
          "name": {
           "type": "string"
          },
          "namespace": {
           "type": "string"
          }
         },
         "type": "object"
        }
       },
       "type": "object"
      },
      "managedDraining": {
       "type": "string"
      },
      "managedScaling": {
       "description": "The managed scaling settings for the Auto Scaling group capacity provider.\n\nWhen managed scaling is turned on, Amazon ECS manages the scale-in and scale-out\nactions of the Auto Scaling group. Amazon ECS manages a target tracking scaling\npolicy using an Amazon ECS managed CloudWatch metric with the specified targetCapacity\nvalue as the target value for the metric. For more information, see Using\nmanaged scaling (https://docs.aws.amazon.com/AmazonECS/latest/developerguide/asg-capacity-providers.html#asg-capacity-providers-managed-scaling)\nin the Amazon Elastic Container Service Developer Guide.\n\nIf managed scaling is off, the user must manage the scaling of the Auto Scaling\ngroup.",
       "properties": {
        "instanceWarmupPeriod": {
         "format": "int64",
         "type": "integer"
        },
        "maximumScalingStepSize": {
         "format": "int64",
         "type": "integer"
        },
        "minimumScalingStepSize": {
         "format": "int64",
         "type": "integer"
        },
        "status": {
         "type": "string"
        },
        "targetCapacity": {
         "format": "int64",
         "type": "integer"
        }
       },
       "type": "object"
      },
      "managedTerminationProtection": {
       "type": "string"
      }
     },
     "type": "object"
    },
    "cluster": {
     "description": "The name of the cluster to associate with the capacity provider. When you\ncreate a capacity provider with Amazon ECS Managed Instances, it becomes\navailable only within the specified cluster.",
     "type": "string",
     "x-kubernetes-validations": [
      {
       "message": "Value is immutable once set",
       "rule": "self == oldSelf"
      }
     ]
    },
    "clusterRef": {
     "description": "AWSResourceReferenceWrapper provides a wrapper around *AWSResourceReference\ntype to provide more user friendly syntax for references using 'from' field\nEx:\nAPIIDRef:\n\n\tfrom:\n\t  name: my-api",
     "properties": {
      "from": {
       "description": "AWSResourceReference provides all the values necessary to reference another\nk8s resource for finding the identifier(Id/ARN/Name)",
       "properties": {
        "name": {
         "type": "string"
        },
        "namespace": {
         "type": "string"
        }
       },
       "type": "object"
      }
     },
     "type": "object"
    },
    "managedInstancesProvider": {
     "description": "The configuration for the Amazon ECS Managed Instances provider. This configuration\nspecifies how Amazon ECS manages Amazon EC2 instances on your behalf, including\nthe infrastructure role, instance launch template, and tag propagation settings.",
     "properties": {
      "autoRepairConfiguration": {
       "description": "The auto repair configuration for an Amazon ECS Managed Instances capacity\nprovider. When enabled, Amazon ECS automatically replaces container instances\nthat are detected as unhealthy based on container instance health checks,\nincluding accelerated compute device and daemon health checks.",
       "properties": {
        "actionsStatus": {
         "type": "string"
        }
       },
       "type": "object"
      },
      "infrastructureOptimization": {
       "description": "The configuration that controls how Amazon ECS optimizes your infrastructure.",
       "properties": {
        "scaleInAfter": {
         "format": "int64",
         "type": "integer"
        }
       },
       "type": "object"
      },
      "infrastructureRoleARN": {
       "type": "string"
      },
      "infrastructureRoleRef": {
       "description": "Reference field for InfrastructureRoleARN",
       "properties": {
        "from": {
         "description": "AWSResourceReference provides all the values necessary to reference another\nk8s resource for finding the identifier(Id/ARN/Name)",
         "properties": {
          "name": {
           "type": "string"
          },
          "namespace": {
           "type": "string"
          }
         },
         "type": "object"
        }
       },
       "type": "object"
      },
      "instanceLaunchTemplate": {
       "description": "The launch template configuration for Amazon ECS Managed Instances. This\ndefines how Amazon ECS launches Amazon EC2 instances, including the instance\nprofile for your tasks, network and storage configuration, capacity options,\nand instance requirements for flexible instance type selection.",
       "properties": {
        "capacityOptionType": {
         "type": "string"
        },
        "capacityReservations": {
         "description": "The Capacity Reservation configurations to be used when using the RESERVED\ncapacity option type.",
         "properties": {
          "reservationGroupARN": {
           "type": "string"
          },
          "reservationPreference": {
           "type": "string"
          }
         },
         "type": "object"
        },
        "ec2InstanceProfileARN": {
         "type": "string"
        },
        "ec2InstanceProfileRef": {
         "description": "Reference field for EC2InstanceProfileARN",
         "properties": {
          "from": {
           "description": "AWSResourceReference provides all the values necessary to reference another\nk8s resource for finding the identifier(Id/ARN/Name)",
           "properties": {
            "name": {
             "type": "string"
            },
            "namespace": {
             "type": "string"
            }
           },
           "type": "object"
          }
         },
         "type": "object"
        },
        "fipsEnabled": {
         "type": "boolean"
        },
        "instanceMetadataTagsPropagation": {
         "type": "boolean"
        },
        "instanceRequirements": {
         "description": "The instance requirements for attribute-based instance type selection. Instead\nof specifying exact instance types, you define requirements such as vCPU\ncount, memory size, network performance, and accelerator specifications.\nAmazon ECS automatically selects Amazon EC2 instance types that match these\nrequirements, providing flexibility and helping to mitigate capacity constraints.",
         "properties": {
          "acceleratorCount": {
           "description": "The minimum and maximum number of accelerators (such as GPUs) for instance\ntype selection. This is used for workloads that require specific numbers\nof accelerators.",
           "properties": {
            "max": {
             "format": "int64",
             "type": "integer"
            },
            "min": {
             "format": "int64",
             "type": "integer"
            }
           },
           "type": "object"
          },
          "acceleratorManufacturers": {
           "items": {
            "type": "string"
           },
           "type": "array"
          },
          "acceleratorNames": {
           "items": {
            "type": "string"
           },
           "type": "array"
          },
          "acceleratorTotalMemoryMiB": {
           "description": "The minimum and maximum total accelerator memory in mebibytes (MiB) for instance\ntype selection. This is important for GPU workloads that require specific\namounts of video memory.",
           "properties": {
            "max": {
             "format": "int64",
             "type": "integer"
            },
            "min": {
             "format": "int64",
             "type": "integer"
            }
           },
           "type": "object"
          },
          "acceleratorTypes": {
           "items": {
            "type": "string"
           },
           "type": "array"
          },
          "allowedInstanceTypes": {
           "items": {
            "type": "string"
           },
           "type": "array"
          },
          "bareMetal": {
           "type": "string"
          },
          "baselineEBSBandwidthMbps": {
           "description": "The minimum and maximum baseline Amazon EBS bandwidth in megabits per second\n(Mbps) for instance type selection. This is important for workloads with\nhigh storage I/O requirements.",
           "properties": {
            "max": {
             "format": "int64",
             "type": "integer"
            },
            "min": {
             "format": "int64",
             "type": "integer"
            }
           },
           "type": "object"
          },
          "burstablePerformance": {
           "type": "string"
          },
          "cpuManufacturers": {
           "items": {
            "type": "string"
           },
           "type": "array"
          },
          "excludedInstanceTypes": {
           "items": {
            "type": "string"
           },
           "type": "array"
          },
          "instanceGenerations": {
           "items": {
            "type": "string"
           },
           "type": "array"
          },
          "localStorage": {
           "type": "string"
          },
          "localStorageTypes": {
           "items": {
            "type": "string"
           },
           "type": "array"
          },
          "maxSpotPriceAsPercentageOfOptimalOnDemandPrice": {
           "format": "int64",
           "type": "integer"
          },
          "memoryGiBPerVCPU": {
           "description": "The minimum and maximum amount of memory per vCPU in gibibytes (GiB). This\nhelps ensure that instance types have the appropriate memory-to-CPU ratio\nfor your workloads.",
           "properties": {
            "max": {
             "type": "number"
            },
            "min": {
             "type": "number"
            }
           },
           "type": "object"
          },
          "memoryMiB": {
           "description": "The minimum and maximum amount of memory in mebibytes (MiB) for instance\ntype selection. This ensures that selected instance types have adequate memory\nfor your workloads.",
           "properties": {
            "max": {
             "format": "int64",
             "type": "integer"
            },
            "min": {
             "format": "int64",
             "type": "integer"
            }
           },
           "type": "object"
          },
          "networkBandwidthGbps": {
           "description": "The minimum and maximum network bandwidth in gigabits per second (Gbps) for\ninstance type selection. This is important for network-intensive workloads.",
           "properties": {
            "max": {
             "type": "number"
            },
            "min": {
             "type": "number"
            }
           },
           "type": "object"
          },
          "networkInterfaceCount": {
           "description": "The minimum and maximum number of network interfaces for instance type selection.\nThis is useful for workloads that require multiple network interfaces.",
           "properties": {
            "max": {
             "format": "int64",
             "type": "integer"
            },
            "min": {
             "format": "int64",
             "type": "integer"
            }
           },
           "type": "object"
          },
          "onDemandMaxPricePercentageOverLowestPrice": {
           "format": "int64",
           "type": "integer"
          },
          "requireHibernateSupport": {
           "type": "boolean"
          },
          "spotMaxPricePercentageOverLowestPrice": {
           "format": "int64",
           "type": "integer"
          },
          "totalLocalStorageGB": {
           "description": "The minimum and maximum total local storage in gigabytes (GB) for instance\ntypes with local storage. This is useful for workloads that require local\nstorage for temporary data or caching.",
           "properties": {
            "max": {
             "type": "number"
            },
            "min": {
             "type": "number"
            }
           },
           "type": "object"
          },
          "vCPUCount": {
           "description": "The minimum and maximum number of vCPUs for instance type selection. This\nallows you to specify a range of vCPU counts that meet your workload requirements.",
           "properties": {
            "max": {
             "format": "int64",
             "type": "integer"
            },
            "min": {
             "format": "int64",
             "type": "integer"
            }
           },
           "type": "object"
          }
         },
         "type": "object"
        },
        "localStorageConfiguration": {
         "description": "The local storage configuration for Amazon ECS Managed Instances. This defines\nhow ECS uses and configures instance store volumes available on container\ninstance.",
         "properties": {
          "useLocalStorage": {
           "type": "boolean"
          }
         },
         "type": "object"
        },
        "monitoring": {
         "type": "string"
        },
        "networkConfiguration": {
         "description": "The network configuration for Amazon ECS Managed Instances. This specifies\nthe VPC subnets and security groups that instances use for network connectivity.\nAmazon ECS Managed Instances support multiple network modes including awsvpc\n(instances receive ENIs for task isolation), host (instances share network\nnamespace with tasks), and none (no external network connectivity), ensuring\nbackward compatibility for migrating workloads from Fargate or Amazon EC2.",
         "properties": {
          "securityGroupRefs": {
           "description": "Reference field for SecurityGroups",
           "items": {
            "description": "AWSResourceReferenceWrapper provides a wrapper around *AWSResourceReference\ntype to provide more user friendly syntax for references using 'from' field\nEx:\nAPIIDRef:\n\n\tfrom:\n\t  name: my-api",
            "properties": {
             "from": {
              "description": "AWSResourceReference provides all the values necessary to reference another\nk8s resource for finding the identifier(Id/ARN/Name)",
              "properties": {
               "name": {
                "type": "string"
               },
               "namespace": {
                "type": "string"
               }
              },
              "type": "object"
             }
            },
            "type": "object"
           },
           "type": "array"
          },
          "securityGroups": {
           "items": {
            "type": "string"
           },
           "type": "array"
          },
          "subnetRefs": {
           "description": "Reference field for Subnets",
           "items": {
            "description": "AWSResourceReferenceWrapper provides a wrapper around *AWSResourceReference\ntype to provide more user friendly syntax for references using 'from' field\nEx:\nAPIIDRef:\n\n\tfrom:\n\t  name: my-api",
            "properties": {
             "from": {
              "description": "AWSResourceReference provides all the values necessary to reference another\nk8s resource for finding the identifier(Id/ARN/Name)",
              "properties": {
               "name": {
                "type": "string"
               },
               "namespace": {
                "type": "string"
               }
              },
              "type": "object"
             }
            },
            "type": "object"
           },
           "type": "array"
          },
          "subnets": {
           "items": {
            "type": "string"
           },
           "type": "array"
          }
         },
         "type": "object"
        },
        "storageConfiguration": {
         "description": "The storage configuration for Amazon ECS Managed Instances. This defines\nthe data volume configuration for the instances.",
         "properties": {
          "storageSizeGiB": {
           "format": "int64",
           "type": "integer"
          }
         },
         "type": "object"
        }
       },
       "type": "object"
      },
      "propagateTags": {
       "type": "string"
      }
     },
     "type": "object"
    },
    "name": {
     "description": "The name of the capacity provider. Up to 255 characters are allowed. They\ninclude letters (both upper and lowercase letters), numbers, underscores\n(_), and hyphens (-). The name can't be prefixed with \"aws\", \"ecs\", or \"fargate\".",
     "type": "string",
     "x-kubernetes-validations": [
      {
       "message": "Value is immutable once set",
       "rule": "self == oldSelf"
      }
     ]
    },
    "tags": {
     "description": "The metadata that you apply to the capacity provider to categorize and organize\nthem more conveniently. Each tag consists of a key and an optional value.\nYou define both of them.\n\nThe following basic restrictions apply to tags:\n\n  - Maximum number of tags per resource - 50\n\n  - For each resource, each tag key must be unique, and each tag key can\n    have only one value.\n\n  - Maximum key length - 128 Unicode characters in UTF-8\n\n  - Maximum value length - 256 Unicode characters in UTF-8\n\n  - If your tagging schema is used across multiple services and resources,\n    remember that other services may have restrictions on allowed characters.\n    Generally allowed characters are: letters, numbers, and spaces representable\n    in UTF-8, and the following characters: + - = . _ : / @.\n\n  - Tag keys and values are case-sensitive.\n\n  - Do not use aws:, AWS:, or any upper or lowercase combination of such\n    as a prefix for either keys or values as it is reserved for Amazon Web\n    Services use. You cannot edit or delete tag keys or values with this prefix.\n    Tags with this prefix do not count against your tags per resource limit.",
     "items": {
      "description": "The metadata that you apply to a resource to help you categorize and organize\nthem. Each tag consists of a key and an optional value. You define them.\n\nThe following basic restrictions apply to tags:\n\n  - Maximum number of tags per resource - 50\n\n  - For each resource, each tag key must be unique, and each tag key can\n    have only one value.\n\n  - Maximum key length - 128 Unicode characters in UTF-8\n\n  - Maximum value length - 256 Unicode characters in UTF-8\n\n  - If your tagging schema is used across multiple services and resources,\n    remember that other services may have restrictions on allowed characters.\n    Generally allowed characters are: letters, numbers, and spaces representable\n    in UTF-8, and the following characters: + - = . _ : / @.\n\n  - Tag keys and values are case-sensitive.\n\n  - Do not use aws:, AWS:, or any upper or lowercase combination of such\n    as a prefix for either keys or values as it is reserved for Amazon Web\n    Services use. You cannot edit or delete tag keys or values with this prefix.\n    Tags with this prefix do not count against your tags per resource limit.",
      "properties": {
       "key": {
        "type": "string"
       },
       "value": {
        "type": "string"
       }
      },
      "type": "object"
     },
     "type": "array"
    }
   },
   "required": [
    "name"
   ],
   "type": "object"
  }
 },
 "title": "Capacity Provider",
 "type": "object"
}
